+import (
+	"encoding/json"
+	"testing"
+	"time"
+
+	"github.com/steveyegge/gastown/internal/mrqueue"
+)
+
+func TestParseMQEventLine(t *testing.T) {
+	tests := []struct {
+		name         string
+		event        mrqueue.Event
+		wantType     string
+		wantTarget   string
+		wantContains string // Substring in message
+	}{
+		{
+			name: "merge_started",
+			event: mrqueue.Event{
+				Timestamp: time.Now(),
+				Type:      mrqueue.EventMergeStarted,
+				MRID:      "mr-123",
+				Branch:    "polecat/nux",
+				Target:    "main",
+				Worker:    "nux",
+				Rig:       "gastown",
+			},
+			wantType:     "merge_started",
+			wantTarget:   "mr-123",
+			wantContains: "Merge started",
+		},
+		{
+			name: "merged",
+			event: mrqueue.Event{
+				Timestamp:   time.Now(),
+				Type:        mrqueue.EventMerged,
+				MRID:        "mr-456",
+				Branch:      "polecat/toast",
+				Target:      "main",
+				Worker:      "toast",
+				Rig:         "gastown",
+				MergeCommit: "abc123def456789",
+			},
+			wantType:     "merged",
+			wantTarget:   "mr-456",
+			wantContains: "abc123de", // Short SHA
+		},
+		{
+			name: "merge_failed",
+			event: mrqueue.Event{
+				Timestamp: time.Now(),
+				Type:      mrqueue.EventMergeFailed,
+				MRID:      "mr-789",
+				Branch:    "polecat/capable",
+				Target:    "main",
+				Worker:    "capable",
+				Rig:       "gastown",
+				Reason:    "conflict in main.go",
+			},
+			wantType:     "merge_failed",
+			wantTarget:   "mr-789",
+			wantContains: "conflict in main.go",
+		},
+		{
+			name: "merge_skipped",
+			event: mrqueue.Event{
+				Timestamp: time.Now(),
+				Type:      mrqueue.EventMergeSkipped,
+				MRID:      "mr-999",
+				Branch:    "polecat/skip",
+				Target:    "main",
+				Reason:    "already merged",
+			},
+			wantType:     "merge_skipped",
+			wantTarget:   "mr-999",
+			wantContains: "already merged",
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			// Marshal to JSON line
+			data, err := json.Marshal(tt.event)
+			if err != nil {
+				t.Fatalf("Failed to marshal event: %v", err)
+			}
+
+			// Parse the line
+			result := parseMQEventLine(string(data))
+			if result == nil {
+				t.Fatal("parseMQEventLine returned nil")
+			}
+
+			if result.Type != tt.wantType {
